INSERT INTO student_resume (id, tenant_id, user_id, contact_phone, contact_email, job_intention, self_intro, educations, projects, internships, honors) VALUES
(1, 1, 2, '13800000002', 'student@stu.test.edu.cn', 'Java后端开发工程师', '计算机科学与技术专业本科在读，熟悉 Java、Spring Boot、MySQL 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在杭州从事Java后端开发工程师相关工作。', '[{"school":"测试学院","major":"计算机科学与技术","degree":"本科","startDate":"2022-09","endDate":"2026-06","gpa":"3.55/4.0"}]', '[{"name":"计算机科学与技术综合实训 · MySQL实践项目","role":"核心开发","startDate":"2025-03","endDate":"2025-07","description":"使用 MySQL、Redis、Linux 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["MySQL","Redis","Linux"]},{"name":"校园信息服务平台","role":"组员","startDate":"2024-09","endDate":"2025-01","description":"参与需求梳理与 Git、Redis 相关模块开发，负责其中约 40% 的编码量。","skills":["Git","Redis"]}]', '[]', '["CET-6（546 分）","全国大学生数学建模竞赛省二等奖"]'),
(2, 1, 5, '13811000001', 'chenjiayi@stu.test.edu.cn', '后端开发工程师', '软件工程专业本科在读，熟悉 Java、MySQL、Vue 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在上海从事后端开发工程师相关工作。', '[{"school":"测试学院","major":"软件工程","degree":"本科","startDate":"2022-09","endDate":"2026-06","gpa":"3.10/4.0"}]', '[{"name":"软件工程综合实训 · Vue实践项目","role":"后端开发","startDate":"2025-03","endDate":"2025-07","description":"使用 Vue、JavaScript、Git 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["Vue","JavaScript","Git"]},{"name":"校园实验管理平台","role":"核心开发","startDate":"2024-09","endDate":"2025-01","description":"参与需求梳理与 Git、MySQL 相关模块开发，负责其中约 40% 的编码量。","skills":["Git","MySQL"]}]', '[{"company":"天翼软件股份有限公司","position":"后端开发工程师实习生","startDate":"2025-07","endDate":"2025-09","description":"参与线上业务模块迭代，独立承担 2 个需求的开发与自测，代码通过 Code Review 合入主干。"}]', '["软件设计师（中级）","“互联网+”大学生创新创业大赛校赛金奖","全国大学生数学建模竞赛省二等奖"]'),
(3, 1, 6, '13811000002', 'lihaoran@stu.test.edu.cn', '大数据开发工程师', '数据科学与大数据技术专业本科在读，熟悉 Python、SQL、Spark 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在北京从事大数据开发工程师相关工作。', '[{"school":"测试学院","major":"数据科学与大数据技术","degree":"本科","startDate":"2022-09","endDate":"2026-06","gpa":"3.71/4.0"}]', '[{"name":"数据科学与大数据技术综合实训 · Spark实践项目","role":"负责人","startDate":"2025-03","endDate":"2025-07","description":"使用 Spark、SQL、Python 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["Spark","SQL","Python"]}]', '[]', '["蓝桥杯省赛一等奖","软件设计师（中级）"]'),
(4, 1, 7, '13811000003', 'wangyutong@stu.test.edu.cn', '算法工程师', '人工智能专业硕士在读，熟悉 Python、机器学习、深度学习 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在北京从事算法工程师相关工作。', '[{"school":"测试学院","major":"人工智能","degree":"硕士","startDate":"2023-09","endDate":"2026-06","gpa":"3.68/4.0"}]', '[{"name":"人工智能综合实训 · Python实践项目","role":"负责人","startDate":"2025-03","endDate":"2025-07","description":"使用 Python、深度学习、PyTorch 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["Python","深度学习","PyTorch"]},{"name":"校园竞赛训练平台","role":"组员","startDate":"2024-09","endDate":"2025-01","description":"参与需求梳理与 Python、机器学习 相关模块开发，负责其中约 40% 的编码量。","skills":["Python","机器学习"]}]', '[]', '["优秀学生干部","校级一等奖学金"]'),
(5, 1, 8, '13811000004', 'zhangzimo@stu.test.edu.cn', 'Java后端开发工程师', '计算机科学与技术专业本科在读，熟悉 C++、数据结构、Linux 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在深圳从事Java后端开发工程师相关工作。', '[{"school":"测试学院","major":"计算机科学与技术","degree":"本科","startDate":"2022-09","endDate":"2026-06","gpa":"3.66/4.0"}]', '[{"name":"计算机科学与技术综合实训 · Python实践项目","role":"后端开发","startDate":"2025-03","endDate":"2025-07","description":"使用 Python、数据结构、Linux 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["Python","数据结构","Linux"]},{"name":"校园信息服务平台","role":"核心开发","startDate":"2024-09","endDate":"2025-01","description":"参与需求梳理与 Linux、C++ 相关模块开发，负责其中约 40% 的编码量。","skills":["Linux","C++"]}]', '[{"company":"乐游互动娱乐有限公司","position":"Java后端开发工程师实习生","startDate":"2025-07","endDate":"2025-09","description":"参与线上业务模块迭代，独立承担 2 个需求的开发与自测，代码通过 Code Review 合入主干。"}]', '["“互联网+”大学生创新创业大赛校赛金奖","全国大学生数学建模竞赛省二等奖","校级一等奖学金"]'),
