INSERT INTO news (id, tenant_id, category, type, title, summary, content, cover_style, source, source_url, link_target, view_count, featured, status, publish_time) VALUES
(1, 1, NULL, 'DATA_CAST', '本平台在库岗位达 186 个，数据分析已就绪', '涵盖 162 个采集岗位与 24 个站内职位，覆盖 10 座主要城市、8 大技术方向，看板与推荐均基于此。', NULL, 'blue', '平台数据播报', NULL, '/admin/dashboard', 202, 1, 1, '2026-07-09 08:10:00'),
(2, 1, 'backend', 'DATA_CAST', 'Java 稳居技能热度榜首', '在全部岗位中，要求 Java 的职位数量最多，其后为 Python、MySQL。后端方向需求持续旺盛。', NULL, 'blue', '平台数据播报', NULL, '/admin/dashboard', 144, 0, 1, '2026-07-09 08:12:00'),
(3, 1, NULL, 'DATA_CAST', '上海、北京、深圳岗位最集中', '按城市分布，上海岗位数领先，北京、深圳紧随其后；杭州、成都为新一线热门去向。', NULL, 'green', '平台数据播报', NULL, '/admin/dashboard', 251, 0, 1, '2026-07-09 08:14:00'),
(4, 1, 'bigdata', 'DATA_CAST', '大数据方向平均薪资领先', '按行业统计，大数据 / 人工智能方向平均薪资高于全站均值，Spark、Flink 等技能溢价明显。', NULL, 'purple', '平台数据播报', NULL, '/admin/employment', 84, 0, 1, '2026-07-09 08:16:00'),
(5, 1, NULL, 'DATA_CAST', '投递转化：87 份投递中已产生 9 个 OFFER', '站内投递共 87 份，其中面试阶段 18 份、录用 9 份；及时完善画像与简历有助于提升转化。', NULL, 'amber', '平台数据播报', NULL, '/admin/employment', 267, 0, 1, '2026-07-09 08:18:00'),
(6, 1, 'backend', 'ARTICLE', '2026 后端开发就业观察：微服务与云原生成标配', '从平台岗位要求看，Spring Boot、微服务、容器化几乎成为后端岗位的默认门槛。', '<p>综合本平台采集到的后端岗位数据，Spring Boot、Spring Cloud、Redis、消息队列（Kafka/RocketMQ）出现频率显著上升。</p><p>建议在校生优先夯实 Java 基础与数据库，再向微服务、容器化（Docker/K8s）延伸，配合一到两个完整项目经历，将明显提升竞争力。</p>', 'blue', '就业指导中心', NULL, NULL, 183, 1, 1, '2026-07-06 10:00:00'),
(7, 1, 'frontend', 'ARTICLE', '前端招聘趋势：工程化与框架深度并重', '企业更看重 Vue/React 的工程化实践与组件设计能力，而非仅会写页面。', '<p>平台前端岗位中，Vue、TypeScript、构建工具（Vite/Webpack）、组件化设计是高频关键词。</p><p>建议同学在掌握一个主流框架的基础上，理解其响应式原理与工程化配置，并积累可展示的项目。</p>', 'green', '就业指导中心', NULL, NULL, 142, 0, 1, '2026-07-05 14:30:00'),
(8, 1, NULL, 'EXTERNAL', '示例：外部就业资讯（接入开源中国 RSS 后在此展示）', '外部资讯仅展示标题与摘要，点击「阅读原文」跳转来源站点；封面用色块占位。', NULL, 'purple', '开源中国', 'https://www.oschina.net/news', NULL, 230, 0, 1, '2026-07-08 09:00:00');
